function speedToPercent(speed)
    local maxSpeed = 0.1
    return speed / maxSpeed
end

function percentToSpeed(percent)
    local maxSpeed = 0.1
    return percent * maxSpeed
end

function pressEKey()
    keypress(0x45)
    task.wait(0.05)
    keyrelease(0x45)
end

function returnToStartPosition()
    local character = player.Character
    if character and character:FindFirstChild("HumanoidRootPart") and orbitStartPosition then
        pcall(function()
            character.HumanoidRootPart.Position = orbitStartPosition
        end)
        notify("returned to start", "orbit", 5)
    end
end

function returnToVoidStartPosition()
    local character = player.Character
    if character and character:FindFirstChild("HumanoidRootPart") and voidStartPosition then
        pcall(function()
            character.HumanoidRootPart.Position = voidStartPosition
        end)
        voidStartPosition = nil
        notify("returned from void", "void", 5)
    end
end

function stopOrbitAndReturn(reason)
    if orbitEnabled or orbitActive then
        orbitEnabled = false
        orbitActive = false
        teleporting = false
        Switch12_IsChecked = false
        Switch12_IndBorder.Position = Switch12.Position + Vector2.new(1, 1)
        Switch12_Ind.Position = Switch12.Position + Vector2.new(1, 1)
        returnToStartPosition()
        if reason then
            notify(reason, "orbit", 5)
        end
    end
end

function sortPlayersAlphabetically(players)
    local playerNames = {}
    for _, plr in ipairs(players) do
        if plr ~= player then
            table.insert(playerNames, plr.Name)
        end
    end
    table.sort(playerNames, function(a, b)
        return a:lower() < b:lower()
    end)
    
    local sortedPlayers = {}
    for _, name in ipairs(playerNames) do
        for _, plr in ipairs(players) do
            if plr.Name == name then
                table.insert(sortedPlayers, plr)
                break
            end
        end
    end
    return sortedPlayers
end

