            if Slider25_Knob.Visible and mPos.X >= Slider25_Knob.Position.X and mPos.X <= Slider25_Knob.Position.X + Slider25_Knob.Size.X and
               mPos.Y >= Slider25_Knob.Position.Y and mPos.Y <= Slider25_Knob.Position.Y + Slider25_Knob.Size.Y then
                dragging = Slider25_Knob
                dragStart = mPos
                startPos = Slider25_Knob.Position
            end
        end
        
        if not mouse1 and lastMouse1 then
            dragging = nil
        end
        
        if dragging and mouse1 then
            local delta = mPos - dragStart
            dragging.Position = startPos + delta
            if dragging == Slider3_Knob then
                local minX = Slider3.Position.X
                local maxX = Slider3.Position.X + Slider3.Size.X
                if dragging.Position.X < minX then dragging.Position = Vector2.new(minX, dragging.Position.Y) end
                if dragging.Position.X > maxX then dragging.Position = Vector2.new(maxX, dragging.Position.Y) end
                dragging.Position = Vector2.new(dragging.Position.X, Slider3.Position.Y + 5 - dragging.Size.Y/2)
                local percent = (dragging.Position.X - minX) / (Slider3.Size.X)
                local value = 1 + (30 - 1) * percent
                Slider3_Value = value
                Slider3_ValueText.Text = tostring(math.floor(value)) .. ""
                pcall(function() onChanged(value) end)
            end
            if dragging == Slider25_Knob then
                local minX = Slider25.Position.X
                local maxX = Slider25.Position.X + Slider25.Size.X
                if dragging.Position.X < minX then dragging.Position = Vector2.new(minX, dragging.Position.Y) end
                if dragging.Position.X > maxX then dragging.Position = Vector2.new(maxX, dragging.Position.Y) end
                dragging.Position = Vector2.new(dragging.Position.X, Slider25.Position.Y + 5 - dragging.Size.Y/2)
                local percent = (dragging.Position.X - minX) / (Slider25.Size.X)
                local value = 0 + (0.1 - 0) * percent
                Slider25_Value = value
                Slider25_ValueText.Text = tostring(math.floor(value)) .. ""
                pcall(function() onChanged(value) end)
            end
            if dragging == Square1 then
                Slider3.Position = dragging.Position + Vector2.new(23, 175.5)
                local percent = (Slider3_Value - 1) / (30 - 1)
                Slider3_Knob.Position = Slider3.Position + Vector2.new(189 * percent - 10, 5 - 10)
                Slider3_ValueText.Position = Slider3.Position + Vector2.new(189/2, -10)
                Text5.Position = dragging.Position + Vector2.new(38, 24)
                Square8.Position = dragging.Position + Vector2.new(18.5, 17)
                Square8_Border.Position = Square8.Position
                Dropdown9.Position = dragging.Position + Vector2.new(12, 203.5)
                Dropdown9_Text.Position = Dropdown9.Position + Vector2.new(5, 8)
                Dropdown9_Arrow.Position = Dropdown9.Position + Vector2.new(205 - 20, 8)
                for i, item in ipairs(Dropdown9_Items) do
                    if item.Box then
                        item.Box.Position = Dropdown9.Position + Vector2.new(0, 32 * i)
                        item.Text.Position = item.Box.Position + Vector2.new(5, 8)
                    end
                end
                Switch12.Position = dragging.Position + Vector2.new(13.5, 280)
                Switch12_Bg.Position = Switch12.Position
                Switch12_Label.Position = Switch12.Position + Vector2.new(50, 5)
                if Switch12_IsChecked then
                    Switch12_IndBorder.Position = Switch12.Position + Vector2.new(15, 1)
                    Switch12_Ind.Position = Switch12.Position + Vector2.new(15, 1)
                else
                    Switch12_IndBorder.Position = Switch12.Position + Vector2.new(1, 1)
                    Switch12_Ind.Position = Switch12.Position + Vector2.new(1, 1)
                end
                Text13.Position = dragging.Position + Vector2.new(64.5, 134)
                Square14.Position = dragging.Position + Vector2.new(19, 134)
                Square14_Border.Position = Square14.Position
                Square15.Position = dragging.Position + Vector2.new(13.5, 250)
                Square15_Border.Position = Square15.Position
                Text16.Position = dragging.Position + Vector2.new(81, 250)
                Keybind17.Position = dragging.Position + Vector2.new(115.5, 280)
                Keybind17_Text.Position = Keybind17.Position + Vector2.new(100/2, 30/2)
                Switch21.Position = dragging.Position + Vector2.new(12, 321)
                Switch21_Bg.Position = Switch21.Position
                Switch21_Label.Position = Switch21.Position + Vector2.new(50, 5)
                if Switch21_IsChecked then
                    Switch21_IndBorder.Position = Switch21.Position + Vector2.new(15, 1)
                    Switch21_Ind.Position = Switch21.Position + Vector2.new(15, 1)
                else
                    Switch21_IndBorder.Position = Switch21.Position + Vector2.new(1, 1)
                    Switch21_Ind.Position = Switch21.Position + Vector2.new(1, 1)
                end
                Keybind22.Position = dragging.Position + Vector2.new(115.5, 321)
                Keybind22_Text.Position = Keybind22.Position + Vector2.new(100/2, 30/2)
                Square23.Position = dragging.Position + Vector2.new(20, 64)
                Square23_Border.Position = Square23.Position
                Text24.Position = dragging.Position + Vector2.new(64.5, 64)
                Slider25.Position = dragging.Position + Vector2.new(25.5, 109.5)
                local percent = (Slider25_Value - 0) / (0.1 - 0)
                Slider25_Knob.Position = Slider25.Position + Vector2.new(189 * percent - 10, 5 - 10)
                Slider25_ValueText.Position = Slider25.Position + Vector2.new(189/2, -10)
                Switch28.Position = dragging.Position + Vector2.new(12, 362)
                Switch28_Bg.Position = Switch28.Position
                Switch28_Label.Position = Switch28.Position + Vector2.new(50, 5)
                if Switch28_IsChecked then
                    Switch28_IndBorder.Position = Switch28.Position + Vector2.new(15, 1)
                    Switch28_Ind.Position = Switch28.Position + Vector2.new(15, 1)
                else
                    Switch28_IndBorder.Position = Switch28.Position + Vector2.new(1, 1)
                    Switch28_Ind.Position = Switch28.Position + Vector2.new(1, 1)
                end
                Keybind29.Position = dragging.Position + Vector2.new(114, 362)
                Keybind29_Text.Position = Keybind29.Position + Vector2.new(100/2, 30/2)
                Keybind30.Position = dragging.Position + Vector2.new(61, 459)
                Keybind30_Text.Position = Keybind30.Position + Vector2.new(100/2, 30/2)
                Text31.Position = dragging.Position + Vector2.new(64.5, 435)
                Square32.Position = dragging.Position + Vector2.new(10, 434)
                Square32_Border.Position = Square32.Position
            end
        end
        
        lastMouse1 = mouse1
    end
end

